import re
import pandas as pd

# Load data
with open(locals()['var_function-call-2121501170623890719'], 'r') as f:
    books = json.load(f)

with open(locals()['var_function-call-18001450288197137579'], 'r') as f:
    reviews = json.load(f)

# Helper to extract ID number
def get_id_num(s):
    # s is like "bookid_123" or "purchaseid_123"
    parts = s.split('_')
    if len(parts) > 1 and parts[1].isdigit():
        return int(parts[1])
    return None

# Helper to extract year
def extract_year(text):
    if not text:
        return None
    # Priority 1: "on Month Day, Year"
    m = re.search(r'on\s+[A-Z][a-z]+\s+\d{1,2},\s+(\d{4})', text)
    if m:
        return int(m.group(1))

    # Priority 2: "published ... Year" (general check)
    # Search for all 4 digit years
    years = re.findall(r'\b(19\d{2}|20\d{2})\b', text)
    if years:
        # If multiple, usually the first one mentions publication, others might be reprints or ISBNs (though ISBNs don't look like years usually, but 19xx might appear)
        # However, looking at samples, the "on ..." pattern is very common.
        # If "on" pattern failed, return the first year found.
        return int(years[0])

    return None

# Map ID -> Decade
book_decade_map = {}
for b in books:
    bid = get_id_num(b.get('book_id', ''))
    if bid is not None:
        year = extract_year(b.get('details', ''))
        if year:
            decade = (year // 10) * 10
            book_decade_map[bid] = f"{decade}s"

# Aggregate reviews
decade_stats = {} # decade -> {'ratings': [], 'books': set()}

for r in reviews:
    pid = get_id_num(r.get('purchase_id', ''))
    if pid is not None and pid in book_decade_map:
        dec = book_decade_map[pid]
        if dec not in decade_stats:
            decade_stats[dec] = {'ratings': [], 'books': set()}

        try:
            rt = float(r.get('rating', 0))
            decade_stats[dec]['ratings'].append(rt)
            decade_stats[dec]['books'].add(pid)
        except:
            pass

# Analyze
results = []
for dec, stats in decade_stats.items():
    num_books = len(stats['books'])
    if num_books >= 10:
        avg_rating = sum(stats['ratings']) / len(stats['ratings'])
        results.append({'decade': dec, 'avg_rating': avg_rating, 'num_books': num_books})

# Sort by avg rating descending
results.sort(key=lambda x: x['avg_rating'], reverse=True)

print("__RESULT__:")
print(json.dumps(results))
